import React from "react";

export default function DebtTable() {
  const debts = [
    {
      id: 1,
      customerId: 1001,
      currentBalance: 2500.75,
      creditor: "Barclays",
      debtStatusId: 2
    },
    {
      id: 2,
      customerId: 1002,
      currentBalance: 1200.0,
      creditor: "HSBC",
      debtStatusId: 1
    },
    {
      id: 3,
      customerId: 1003,
      currentBalance: 4500.5,
      creditor: "NatWest",
      debtStatusId: 3
    }
  ];

  return (
    <div className="container">
      <h2>Debt Details</h2>

      <table className="debt-table">
        <thead>
          <tr>
            <th>Id</th>
            <th>Customer Id</th>
            <th>Current Balance</th>
            <th>Creditor</th>
            <th>Debt Status Id</th>
          </tr>
        </thead>

        <tbody>
          {debts.map((debt) => (
            <tr key={debt.id}>
              <td>{debt.id}</td>
              <td>{debt.customerId}</td>
              <td>£{debt.currentBalance.toFixed(2)}</td>
              <td>{debt.creditor}</td>
              <td>{debt.debtStatusId}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}
